def setup_wifi_ap():
    ap = network.WLAN(network.AP_IF)
    ap.active(True)
    ap.config(essid='ESP32-IoT', password='12345678')
    while not ap.active():
        time.sleep(0.1)
    print('AP Mode configured')
    print('IP:', ap.ifconfig()[0])
    return ap

def setup_wifi_sta(ssid, password):
    sta = network.WLAN(network.STA_IF)
    sta.active(True)
    if not sta.isconnected():
        print('Connecting to WiFi...')
        sta.connect(ssid, password)
        timeout = 10
        while not sta.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
        if sta.isconnected():
            print('Connected to WiFi')
            print('IP:', sta.ifconfig()[0])
            return sta
        else:
            print('Failed to connect to WiFi')
            return None
    return sta

def parse_http_headers(data):
    headers = {}
    lines = data.split(b'\r\n')
    for line in lines[1:]:
        if b':' in line:
            key, value = line.split(b':', 1)
            headers[key.decode().strip().lower()] = value.decode().strip()
    return headers

def create_websocket_accept_key(key):
    combined = key + WEBSOCKET_MAGIC_STRING
    sha1 = hashlib.sha1(combined.encode())
    accept_key = binascii.b2a_base64(sha1.digest()).strip()
    return accept_key.decode()

def send_websocket_handshake(client, accept_key):
    response = (
        "HTTP/1.1 101 Switching Protocols\r\n"
        "Upgrade: websocket\r\n"
        "Connection: Upgrade\r\n"
        "Sec-WebSocket-Accept: " + accept_key + "\r\n"
        "\r\n"
    )
    client.send(response.encode())

def decode_websocket_frame(data):
    if len(data) < 2:
        return None
    
    fin = (data[0] & 0x80) >> 7
    opcode = data[0] & 0x0F
    masked = (data[1] & 0x80) >> 7
    payload_length = data[1] & 0x7F
    
    offset = 2
    
    if payload_length == 126:
        if len(data) < 4:
            return None
        payload_length = int.from_bytes(data[2:4], 'big')
        offset = 4
    elif payload_length == 127:
        if len(data) < 10:
            return None
        payload_length = int.from_bytes(data[2:10], 'big')
        offset = 10
    
    if masked:
        if len(data) < offset + 4:
            return None
        masking_key = data[offset:offset+4]
        offset += 4
    else:
        masking_key = None
    
    if len(data) < offset + payload_length:
        return None
    
    payload = bytearray(data[offset:offset+payload_length])
    
    if masked and masking_key:
        for i in range(len(payload)):
            payload[i] ^= masking_key[i % 4]
    
    return {
        'fin': fin,
        'opcode': opcode,
        'payload': bytes(payload),
        'payload_length': payload_length
    }

def encode_websocket_frame(payload, opcode=0x1):
    frame = bytearray()
    frame.append(0x80 | opcode)
    
    payload_bytes = payload.encode() if isinstance(payload, str) else payload
    payload_length = len(payload_bytes)
    
    if payload_length < 126:
        frame.append(payload_length)
    elif payload_length < 65536:
        frame.append(126)
        frame.extend(payload_length.to_bytes(2, 'big'))
    else:
        frame.append(127)
        frame.extend(payload_length.to_bytes(8, 'big'))
    
    frame.extend(payload_bytes)
    return bytes(frame)

def send_websocket_message(client, message):
    try:
        frame = encode_websocket_frame(message)
        client.send(frame)
        return True
    except:
        return False

def handle_command(command):
    try:
        cmd = json.loads(command)
        action = cmd.get('action', '')
        
        if action == 'turn_on':
            led.on()
            return json.dumps({'status': 'success', 'action': 'turn_on', 'state': 'on'})
        elif action == 'turn_off':
            led.off()
            return json.dumps({'status': 'success', 'action': 'turn_off', 'state': 'off'})
        elif action == 'toggle':
            led.value(not led.value())
            state = 'on' if led.value() else 'off'
            return json.dumps({'status': 'success', 'action': 'toggle', 'state': state})
        elif action == 'status':
            state = 'on' if led.value() else 'off'
            return json.dumps({'status': 'success', 'state': state})
        elif action == 'ping':
            return json.dumps({'status': 'success', 'action': 'pong'})
        else:
            return json.dumps({'status': 'error', 'message': 'Unknown action'})
    except Exception as e:
        return json.dumps({'status': 'error', 'message': str(e)})

def handle_websocket_client(client, addr):
    print('WebSocket client connected from', addr)
    try:
        while True:
            data = client.recv(1024)
            if not data:
                break
            
            frame = decode_websocket_frame(data)
            if frame:
                opcode = frame['opcode']
                
                if opcode == 0x8:
                    print('Close frame received')
                    break
                elif opcode == 0x9:
                    pong_frame = encode_websocket_frame(frame['payload'], opcode=0xA)
                    client.send(pong_frame)
                elif opcode == 0x1:
                    message = frame['payload'].decode()
                    print('Received:', message)
                    response = handle_command(message)
                    send_websocket_message(client, response)
    except Exception as e:
        print('WebSocket error:', e)
    finally:
        client.close()
        print('WebSocket client disconnected')

